import{_ as e,o as r,c as s,ag as o}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Internet Services","description":"","frontmatter":{},"headers":[],"relativePath":"theory/internet/internet-services.md","filePath":"theory/internet/internet-services.md"}'),a={name:"theory/internet/internet-services.md"};function n(d,t,i,l,c,h){return r(),s("div",null,[...t[0]||(t[0]=[o(`<h1 id="internet-services" tabindex="-1">Internet Services <a class="header-anchor" href="#internet-services" aria-label="Permalink to &quot;Internet Services&quot;">​</a></h1><p>The internet is more than just websites. Email, file transfer, streaming, voice calls, and real-time communication all run on the same network infrastructure but use different protocols and services designed for each purpose.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11</p><p>Internet services and protocols (HTTP/S, FTP, VoIP, RSS, SEO) are Grade 11 content. Grade 12 extends with scripting and online applications.</p></div><hr><h2 id="overview-of-internet-services" tabindex="-1">Overview of Internet Services <a class="header-anchor" href="#overview-of-internet-services" aria-label="Permalink to &quot;Overview of Internet Services&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Protocol</th><th>Port</th><th>Purpose</th></tr></thead><tbody><tr><td>Web browsing</td><td>HTTP</td><td>80</td><td>Transfer web pages (unencrypted)</td></tr><tr><td>Secure web browsing</td><td>HTTPS</td><td>443</td><td>Transfer web pages (TLS encrypted)</td></tr><tr><td>Email sending</td><td>SMTP</td><td>25 / 587</td><td>Send email messages</td></tr><tr><td>Email retrieval</td><td>POP3</td><td>110</td><td>Download email to device</td></tr><tr><td>Email access</td><td>IMAP</td><td>143</td><td>Access email on server</td></tr><tr><td>File transfer</td><td>FTP</td><td>20/21</td><td>Transfer files between computers</td></tr><tr><td>Secure file transfer</td><td>SFTP / FTPS</td><td>22 / 990</td><td>Encrypted file transfer</td></tr><tr><td>Voice/video calls</td><td>VoIP</td><td>Varies</td><td>Internet-based calls</td></tr><tr><td>Domain name resolution</td><td>DNS</td><td>53</td><td>Convert domain names to IP addresses</td></tr><tr><td>IP address assignment</td><td>DHCP</td><td>67/68</td><td>Assign IP addresses automatically</td></tr><tr><td>News feeds</td><td>RSS</td><td>—</td><td>Subscribe to content updates</td></tr></tbody></table><hr><h2 id="http-and-https" tabindex="-1">HTTP and HTTPS <a class="header-anchor" href="#http-and-https" aria-label="Permalink to &quot;HTTP and HTTPS&quot;">​</a></h2><p><strong>HTTP</strong> (Hypertext Transfer Protocol) is the foundation of data exchange on the web. Every time you visit a website, your browser uses HTTP to request pages from the server.</p><h3 id="http-request-response-cycle" tabindex="-1">HTTP Request-Response Cycle: <a class="header-anchor" href="#http-request-response-cycle" aria-label="Permalink to &quot;HTTP Request-Response Cycle:&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Browser → GET /index.html HTTP/1.1 → Web Server</span></span>
<span class="line"><span>Web Server → 200 OK + HTML content → Browser</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>Common HTTP status codes:</strong></p><table tabindex="0"><thead><tr><th>Code</th><th>Meaning</th></tr></thead><tbody><tr><td>200</td><td>OK — request successful</td></tr><tr><td>301</td><td>Moved Permanently — redirect</td></tr><tr><td>403</td><td>Forbidden — no permission</td></tr><tr><td>404</td><td>Not Found — page doesn&#39;t exist</td></tr><tr><td>500</td><td>Internal Server Error</td></tr></tbody></table><p><strong>HTTPS</strong> = HTTP + <strong>TLS encryption</strong></p><ul><li>All data encrypted before sending</li><li>Certificate verifies server identity</li><li>Port 443 (HTTP uses port 80)</li></ul><hr><h2 id="ftp-—-file-transfer-protocol" tabindex="-1">FTP — File Transfer Protocol <a class="header-anchor" href="#ftp-—-file-transfer-protocol" aria-label="Permalink to &quot;FTP — File Transfer Protocol&quot;">​</a></h2><p><strong>FTP</strong> is used to transfer files between a client and a server over a network.</p><table tabindex="0"><thead><tr><th>Feature</th><th>FTP</th><th>SFTP</th></tr></thead><tbody><tr><td>Encryption</td><td>None</td><td>Yes (SSH)</td></tr><tr><td>Port</td><td>20 (data), 21 (control)</td><td>22</td></tr><tr><td>Security</td><td>Credentials sent in plaintext</td><td>Credentials encrypted</td></tr><tr><td>Use case</td><td>Legacy systems</td><td>Modern secure transfers</td></tr></tbody></table><p><strong>Uses:</strong></p><ul><li>Web developers uploading files to web server</li><li>Downloading large files from servers</li><li>Transferring files between companies</li></ul><hr><h2 id="dns-—-domain-name-system" tabindex="-1">DNS — Domain Name System <a class="header-anchor" href="#dns-—-domain-name-system" aria-label="Permalink to &quot;DNS — Domain Name System&quot;">​</a></h2><p><strong>DNS</strong> translates human-readable domain names into IP addresses.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>www.google.com → 142.250.185.78</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="dns-resolution-process" tabindex="-1">DNS Resolution Process: <a class="header-anchor" href="#dns-resolution-process" aria-label="Permalink to &quot;DNS Resolution Process:&quot;">​</a></h3><ol><li>You type <code>www.example.com</code> in browser</li><li>Browser checks local <strong>DNS cache</strong> — if not found:</li><li>Queries <strong>Recursive resolver</strong> (your ISP&#39;s DNS server)</li><li>Resolver queries <strong>Root nameserver</strong> → directs to TLD nameserver (.com, .co.za)</li><li>TLD nameserver directs to <strong>Authoritative nameserver</strong> for example.com</li><li>Authoritative nameserver returns the IP address</li><li>Browser connects to that IP address</li></ol><p><strong>DNS record types:</strong></p><table tabindex="0"><thead><tr><th>Record</th><th>Purpose</th></tr></thead><tbody><tr><td>A</td><td>Maps domain to IPv4 address</td></tr><tr><td>AAAA</td><td>Maps domain to IPv6 address</td></tr><tr><td>MX</td><td>Mail server for the domain</td></tr><tr><td>CNAME</td><td>Alias — one domain points to another</td></tr><tr><td>TXT</td><td>Text information (used for email security)</td></tr></tbody></table><hr><h2 id="search-engines-and-seo" tabindex="-1">Search Engines and SEO <a class="header-anchor" href="#search-engines-and-seo" aria-label="Permalink to &quot;Search Engines and SEO&quot;">​</a></h2><h3 id="how-search-engines-work" tabindex="-1">How Search Engines Work: <a class="header-anchor" href="#how-search-engines-work" aria-label="Permalink to &quot;How Search Engines Work:&quot;">​</a></h3><ol><li><strong>Crawling</strong> — bots follow links across the web, discovering pages</li><li><strong>Indexing</strong> — discovered pages are analysed and added to the index</li><li><strong>Ranking</strong> — when a user searches, the algorithm ranks relevant results</li></ol><p><strong>Major search engines:</strong> Google, Bing, DuckDuckGo, Baidu</p><h3 id="seo-—-search-engine-optimisation" tabindex="-1">SEO — Search Engine Optimisation <a class="header-anchor" href="#seo-—-search-engine-optimisation" aria-label="Permalink to &quot;SEO — Search Engine Optimisation&quot;">​</a></h3><p><strong>SEO</strong> is the process of improving a website to rank higher in search engine results pages (SERPs).</p><table tabindex="0"><thead><tr><th>SEO Technique</th><th>Description</th></tr></thead><tbody><tr><td><strong>Relevant keywords</strong></td><td>Include search terms users actually use</td></tr><tr><td><strong>Page title and meta description</strong></td><td>Descriptive HTML tags help search engines understand content</td></tr><tr><td><strong>Quality content</strong></td><td>Original, useful, well-written content ranks better</td></tr><tr><td><strong>Backlinks</strong></td><td>Links from other reputable sites improve authority</td></tr><tr><td><strong>Mobile-friendly design</strong></td><td>Google ranks mobile-friendly sites higher</td></tr><tr><td><strong>Page load speed</strong></td><td>Faster sites rank better</td></tr><tr><td><strong>HTTPS</strong></td><td>Secure sites get a ranking boost</td></tr><tr><td><strong>Alt text on images</strong></td><td>Describes images for search engines and accessibility</td></tr></tbody></table><p><strong>White-hat SEO</strong> — legitimate techniques following search engine guidelines<br><strong>Black-hat SEO</strong> — manipulative techniques (keyword stuffing, link farms) — penalised</p><hr><h2 id="cloud-services" tabindex="-1">Cloud Services <a class="header-anchor" href="#cloud-services" aria-label="Permalink to &quot;Cloud Services&quot;">​</a></h2><p><strong>Cloud computing</strong> delivers computing services over the internet — storage, software, processing.</p><table tabindex="0"><thead><tr><th>Model</th><th>What you get</th><th>Examples</th></tr></thead><tbody><tr><td><strong>SaaS</strong></td><td>Ready-to-use software</td><td>Gmail, Microsoft 365, Netflix</td></tr><tr><td><strong>PaaS</strong></td><td>Development platform</td><td>Google App Engine, Heroku</td></tr><tr><td><strong>IaaS</strong></td><td>Virtual hardware</td><td>AWS, Microsoft Azure</td></tr></tbody></table><h3 id="online-storage-services" tabindex="-1">Online Storage Services <a class="header-anchor" href="#online-storage-services" aria-label="Permalink to &quot;Online Storage Services&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Service</th><th>Provider</th><th>Free Storage</th></tr></thead><tbody><tr><td>Google Drive</td><td>Google</td><td>15 GB</td></tr><tr><td>OneDrive</td><td>Microsoft</td><td>5 GB</td></tr><tr><td>Dropbox</td><td>Dropbox</td><td>2 GB</td></tr><tr><td>iCloud</td><td>Apple</td><td>5 GB</td></tr></tbody></table><hr><h2 id="cookies" tabindex="-1">Cookies <a class="header-anchor" href="#cookies" aria-label="Permalink to &quot;Cookies&quot;">​</a></h2><p><strong>Cookies</strong> are small text files stored on your device by websites you visit.</p><p><strong>Types:</strong></p><table tabindex="0"><thead><tr><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Session cookie</strong></td><td>Temporary — expires when browser closes; keeps you logged in during visit</td></tr><tr><td><strong>Persistent cookie</strong></td><td>Stored longer — remembers preferences, login details</td></tr><tr><td><strong>Third-party cookie</strong></td><td>Set by advertisers tracking you across multiple websites</td></tr></tbody></table><p><strong>What cookies do:</strong></p><ul><li>Keep you logged in</li><li>Remember shopping cart contents</li><li>Store user preferences (language, theme)</li><li>Track browsing behaviour for targeted advertising</li><li>Maintain session state</li></ul><p><strong>Privacy considerations:</strong></p><ul><li>GDPR (EU) and POPIA (SA) require consent before non-essential cookies</li><li>Users can clear cookies or block third-party cookies in browser settings</li></ul><hr><h2 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h2><p><strong>Streaming</strong> delivers audio and video as a continuous real-time flow rather than requiring a complete download first.</p><table tabindex="0"><thead><tr><th>Feature</th><th>Download</th><th>Streaming</th></tr></thead><tbody><tr><td>Wait time</td><td>Full download before playback</td><td>Starts almost immediately</td></tr><tr><td>Storage</td><td>Saves file locally</td><td>No local file (unless downloaded)</td></tr><tr><td>Internet needed during playback</td><td>No (after download)</td><td>Yes (constant)</td></tr><tr><td>Buffering</td><td>No</td><td>Yes (if connection drops)</td></tr></tbody></table><p><strong>Adaptive bitrate streaming:</strong> Video quality automatically adjusts based on connection speed (YouTube, Netflix).</p><p><strong>Compression used in streaming:</strong></p><ul><li>Video: H.264, H.265 (HEVC), AV1</li><li>Audio: MP3, AAC, FLAC</li><li>Lossless vs lossy depending on content</li></ul><hr><h2 id="online-applications-vs-desktop-applications" tabindex="-1">Online Applications vs Desktop Applications <a class="header-anchor" href="#online-applications-vs-desktop-applications" aria-label="Permalink to &quot;Online Applications vs Desktop Applications&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>Online App (SaaS)</th><th>Desktop App</th></tr></thead><tbody><tr><td>Installation</td><td>None — runs in browser</td><td>Must be installed</td></tr><tr><td>Updates</td><td>Automatic</td><td>Manual</td></tr><tr><td>Access</td><td>Any device with browser</td><td>Only installed devices</td></tr><tr><td>Internet required</td><td>Yes</td><td>Usually no</td></tr><tr><td>Storage</td><td>Cloud</td><td>Local</td></tr><tr><td>Examples</td><td>Google Docs, Canva</td><td>Microsoft Word, Photoshop</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>HTTP</strong></td><td>Protocol for transferring web pages</td></tr><tr><td><strong>HTTPS</strong></td><td>HTTP with TLS encryption</td></tr><tr><td><strong>FTP</strong></td><td>Protocol for transferring files between computers</td></tr><tr><td><strong>DNS</strong></td><td>Translates domain names to IP addresses</td></tr><tr><td><strong>SEO</strong></td><td>Optimising a website to rank higher in search results</td></tr><tr><td><strong>Cookie</strong></td><td>Small file stored in browser recording visit/preference data</td></tr><tr><td><strong>Streaming</strong></td><td>Delivering media in real-time without full download</td></tr><tr><td><strong>Cloud computing</strong></td><td>Delivery of computing services over the internet</td></tr><tr><td><strong>SaaS</strong></td><td>Software delivered via internet (no installation)</td></tr><tr><td><strong>RSS</strong></td><td>Format for subscribing to content updates from websites</td></tr><tr><td><strong>Adaptive bitrate</strong></td><td>Streaming that adjusts quality based on connection speed</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;What is the difference between HTTP and HTTPS?&quot;</strong> — HTTP transmits data unencrypted (port 80); HTTPS uses TLS to encrypt data and verify server identity (port 443)</p></li><li><p><strong>&quot;What is a cookie? Give TWO uses.&quot;</strong> — small text file stored by a website; uses: keep user logged in; remember preferences; track browsing for advertising; store shopping cart</p></li><li><p><strong>&quot;Explain what DNS does&quot;</strong> — translates human-readable domain names (www.google.com) into IP addresses so browsers can connect to the correct server</p></li><li><p><strong>&quot;What is SEO? Give THREE techniques.&quot;</strong> — Search Engine Optimisation; techniques: relevant keywords; quality content; backlinks from reputable sites; fast loading; HTTPS; mobile-friendly</p></li><li><p><strong>&quot;Give TWO advantages of streaming over downloading&quot;</strong> — playback starts immediately (no wait for full download); no local storage space needed</p></li></ol></div>`,69)])])}const u=e(a,[["render",n]]);export{p as __pageData,u as default};
